import React from "react";

export default function BottomBar({
  onHome,
  onForecast,
  onRadar,
  onChat,
  active = "home", // "home" | "forecast" | "radar" | "chat"
  className = "",
}) {
  const btn = (label, key, onClick, icon) => (
    <button
      onClick={onClick}
      className={[
        "flex flex-col items-center justify-center flex-1 py-2",
        "text-xs font-medium transition",
        active === key ? "text-purple-500" : "text-gray-300 hover:text-white",
      ].join(" ")}
      aria-label={label}
    >
      <div className="text-lg leading-none mb-1">{icon}</div>
      <span>{label}</span>
    </button>
  );

  return (
    <nav
      className={[
        // SHOW ON MOBILE + DESKTOP
        "fixed bottom-0 left-0 right-0 z-40 px-3 pb-[env(safe-area-inset-bottom)]",
        className,
      ].join(" ")}
      aria-label="Bottom navigation"
    >
      <div className="mx-auto max-w-3xl md:max-w-5xl rounded-2xl bg-black/40 backdrop-blur border border-white/10 shadow-lg">
        <div className="flex">
          {btn("Home", "home", onHome, "🏠")}
          {btn("Forecast", "forecast", onForecast, "📅")}
          {btn("Radar", "radar", onRadar, "🛰️")}
          {btn("Chat", "chat", onChat, "💬")}
        </div>
      </div>
    </nav>
  );
}
